'use client'

import { useEffect, useMemo, useState } from 'react'
import TimetableSelector from '@/components/timetable-selector'
import TimetableDisplay from '@/components/timetable-display'
import Footer from '@/components/footer'
import type { ParsedTimetableResponse, TimetableTree } from '@/lib/timetable-types'

const DEFAULT_DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']

function keys<T extends Record<string, unknown> | undefined>(value: T): string[] {
  return value ? Object.keys(value) : []
}

export default function Home() {
  const [timetableData, setTimetableData] = useState<TimetableTree>({})
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [isRefreshing, setIsRefreshing] = useState(false)

  const [department, setDepartment] = useState('')
  const [major, setMajor] = useState('')
  const [year, setYear] = useState('')
  const [section, setSection] = useState('')
  const [day, setDay] = useState('')

  const load = async (shouldRefresh: boolean = false) => {
    try {
      if (shouldRefresh) {
        setIsRefreshing(true)
      } else {
        setLoading(true)
      }
      setError('')

      const url = shouldRefresh ? '/api/timetable?refresh=true' : '/api/timetable'
      const response = await fetch(url, { cache: 'no-store' })
      const json = (await response.json()) as ParsedTimetableResponse | { error: string }

      if (!response.ok || 'error' in json) {
        throw new Error('error' in json ? json.error : 'Failed to load timetable data.')
      }

      setTimetableData(json.data)

      setDepartment('')
      setMajor('')
      setYear('')
      setSection('')
      setDay('')
    } catch (loadError) {
      setTimetableData({})
      setError(loadError instanceof Error ? loadError.message : 'Failed to load timetable data.')
    } finally {
      if (shouldRefresh) {
        setIsRefreshing(false)
      } else {
        setLoading(false)
      }
    }
  }

  useEffect(() => {
    load(false)
  }, [])

  const handleRefresh = () => {
    load(true)
  }

  const departments = useMemo(() => keys(timetableData), [timetableData])
  const majors = useMemo(() => keys(timetableData[department]), [timetableData, department])
  const years = useMemo(() => keys(timetableData[department]?.[major]), [timetableData, department, major])
  const sections = useMemo(
    () => keys(timetableData[department]?.[major]?.[year]),
    [timetableData, department, major, year],
  )
  const days = useMemo(
    () => {
      const parsedDays = keys(timetableData[department]?.[major]?.[year]?.[section])
      return parsedDays.length > 0 ? parsedDays : DEFAULT_DAYS
    },
    [timetableData, department, major, year, section],
  )

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <main className="flex-1 max-w-4xl mx-auto w-full px-4 py-12">
        <div className="mb-12">
          <div className="flex items-center justify-between mb-8">
            <h1 className="text-3xl font-semibold text-black">University Timetable</h1>
            <button
              onClick={handleRefresh}
              disabled={isRefreshing || loading}
              className="px-2 py-1 text-xs font-medium text-black bg-white border border-gray-300 hover:bg-gray-50 disabled:bg-gray-200 disabled:cursor-not-allowed transition-colors"
            >
              {isRefreshing ? 'Refreshing...' : 'Refresh'}
            </button>
          </div>

          {loading ? (
            <p className="mb-6 text-center text-gray-600">Loading timetable from uploads...</p>
          ) : null}

          {error ? <p className="mb-6 text-center text-red-600">{error}</p> : null}

          <TimetableSelector
            departments={departments}
            majors={majors}
            years={years}
            sections={sections}
            days={days}
            department={department}
            setDepartment={setDepartment}
            major={major}
            setMajor={setMajor}
            year={year}
            setYear={setYear}
            section={section}
            setSection={setSection}
            day={day}
            setDay={setDay}
          />
        </div>

        <div className="mt-12">
          <TimetableDisplay
            timetableData={timetableData}
            department={department}
            major={major}
            year={year}
            section={section}
            day={day}
          />
        </div>
      </main>

      <Footer />
    </div>
  )
}
