import type { TimetableTree } from '@/lib/timetable-types'

interface TimetableDisplayProps {
  timetableData: TimetableTree
  department: string
  major: string
  year: string
  section: string
  day: string
}

export default function TimetableDisplay({
  timetableData,
  department,
  major,
  year,
  section,
  day,
}: TimetableDisplayProps) {
  const hasSelection = department && major && year && section && day

  if (!hasSelection) {
    return (
      <div className="text-center py-12">
        <p className="text-gray-600">Select department, major, year, section, and day to view timetable</p>
      </div>
    )
  }

  const schedule = timetableData[department]?.[major]?.[year]?.[section]?.[day] || []

  if (schedule.length === 0) {
    return (
      <div className="text-center py-12">
        <p className="text-gray-600">No classes found</p>
      </div>
    )
  }

  return (
    <div className="overflow-x-auto">
      <table className="w-full border-collapse">
        <thead>
          <tr className="border-b-2 border-black">
            <th className="text-left py-3 px-4 font-semibold text-black">Time</th>
            <th className="text-left py-3 px-4 font-semibold text-black">Course</th>
            <th className="text-left py-3 px-4 font-semibold text-black">Room</th>
          </tr>
        </thead>
        <tbody>
          {schedule.map((slot, index) => (
            <tr key={index} className="border-b border-gray-300">
              <td className="py-3 px-4 text-black">{slot.time}</td>
              <td className="py-3 px-4 text-black">{slot.course}</td>
              <td className="py-3 px-4 text-black">{slot.room}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}
